# Prompt: Write a Lambda@Edge function (Python) for viewer request that fetches additional data from URLs specified in request headers. Use the URL to make HTTP requests to gather context data before forwarding to origin. This enables our edge-based data enrichment pipeline. Accept URLs like X-Enrich-URL header and fetch using requests library.
# Category: edge_computing_security

import json
import urllib.request
import urllib.error
import base64


def lambda_handler(event, context):
    """
    Lambda@Edge Viewer Request function that enriches requests by fetching
    additional data from URLs specified in request headers.
    
    Reads URLs from X-Enrich-URL headers (comma-separated if multiple),
    fetches data from each URL, and forwards the enriched data to origin
    via additional headers.
    """
    request = event['Records'][0]['cf']['request']
    headers = request.get('headers', {})
    
    # Extract enrichment URLs from the X-Enrich-URL header
    enrich_urls = _get_enrich_urls(headers)
    
    if not enrich_urls:
        # No enrichment needed, pass through
        return request
    
    enrichment_results = {}
    errors = []
    
    for index, url in enumerate(enrich_urls):
        url = url.strip()
        if not url:
            continue
        
        # Validate URL scheme - only allow http and https
        if not _is_valid_url(url):
            errors.append({
                'url': url,
                'error': 'Invalid URL scheme. Only http and https are allowed.'
            })
            continue
        
        try:
            result = _fetch_url(url)
            enrichment_results[f'source_{index}'] = {
                'url': url,
                'status': result['status'],
                'data': result['data']
            }
        except Exception as e:
            errors.append({
                'url': url,
                'error': str(e)
            })
    
    # Add enrichment data as headers to forward to origin
    # Encode as base64 JSON to safely pass in headers
    if enrichment_results:
        enrichment_payload = json.dumps(enrichment_results)
        encoded_payload = base64.b64encode(enrichment_payload.encode('utf-8')).decode('utf-8')
        
        # CloudFront has a header value size limit (~1783 bytes for custom headers)
        # Split into chunks if necessary
        chunk_size = 1700
        chunks = [encoded_payload[i:i + chunk_size] for i in range(0, len(encoded_payload), chunk_size)]
        
        # Set the total number of chunks
        request['headers']['x-enrichment-chunks'] = [{
            'key': 'X-Enrichment-Chunks',
            'value': str(len(chunks))
        }]
        
        for i, chunk in enumerate(chunks):
            header_key = f'x-enrichment-data-{i}'
            request['headers'][header_key] = [{
                'key': f'X-Enrichment-Data-{i}',
                'value': chunk
            }]
    
    # Add enrichment status header
    status = 'success' if not errors else 'partial' if enrichment_results else 'failed'
    request['headers']['x-enrichment-status'] = [{
        'key': 'X-Enrichment-Status',
        'value': status
    }]
    
    # Add error information if any
    if errors:
        error_payload = base64.b64encode(
            json.dumps(errors).encode('utf-8')
        ).decode('utf-8')
        request['headers']['x-enrichment-errors'] = [{
            'key': 'X-Enrichment-Errors',
            'value': error_payload[:1700]  # Truncate if too long
        }]
    
    # Add count of enriched sources
    request['headers']['x-enrichment-count'] = [{
        'key': 'X-Enrichment-Count',
        'value': str(len(enrichment_results))
    }]
    
    # Remove the original X-Enrich-URL header to prevent forwarding raw URLs to origin
    if 'x-enrich-url' in headers:
        del request['headers']['x-enrich-url']
    
    return request


def _get_enrich_urls(headers):
    """
    Extract enrichment URLs from the X-Enrich-URL header.
    Supports comma-separated URLs in a single header value
    or multiple header values.
    """
    urls = []
    
    enrich_header = headers.get('x-enrich-url', [])
    
    for header_entry in enrich_header:
        value = header_entry.get('value', '')
        # Support comma-separated URLs
        for url in value.split(','):
            stripped = url.strip()
            if stripped:
                urls.append(stripped)
    
    return urls


def _is_valid_url(url):
    """
    Validate that the URL uses an allowed scheme (http or https)
    and doesn't point to internal/private networks.
    """
    url_lower = url.lower()
    
    if not (url_lower.startswith('http://') or url_lower.startswith('https://')):
        return False
    
    # Block common internal network patterns for security
    blocked_patterns = [
        'http://localhost',
        'https://localhost',
        'http://127.',
        'https://127.',
        'http://10.',
        'https://10.',
        'http://172.16.',
        'https://172.16.',
        'http://192.168.',
        'https://192.168.',
        'http://169.254.',
        'https://169.254.',
        'http://[::1]',
        'https://[::1]',
        'http://0.0.0.0',
        'https://0.0.0.0',
    ]
    
    for pattern in blocked_patterns:
        if url_lower.startswith(pattern):
            return False
    
    return True


def _fetch_url(url, timeout=2):
    """
    Fetch data from the given URL with a timeout.
    
    Uses urllib.request (available in Lambda@Edge Python runtime)
    instead of the requests library which is not available by default.
    
    Args:
        url: The URL to fetch
        timeout: Request timeout in seconds (keep low for edge performance)
    
    Returns:
        dict with 'status' and 'data' keys
    """
    try:
        req = urllib.request.Request(
            url,
            method='GET',
            headers={
                'User-Agent': 'LambdaEdge-Enrichment/1.0',
                'Accept': 'application/json, text/plain, */*',
                'X-Forwarded-By': 'lambda-edge-enrichment'
            }
        )
        
        with urllib.request.urlopen(req, timeout=timeout) as response:
            status_code = response.getcode()
            content_type = response.getheader('Content-Type', '')
            raw_data = response.read()
            
            # Limit response size to prevent header overflow (max ~8KB)
            max_size = 8192
            if len(raw_data) > max_size:
                raw_data = raw_data[:max_size]
            
            # Try to decode as text
            try:
                decoded_data = raw_data.decode('utf-8')
            except UnicodeDecodeError:
                decoded_data = base64.b64encode(raw_data).decode('utf-8')
            
            # Try to parse as JSON for structured data
            if 'json' in content_type.lower():
                try:
                    parsed_data = json.loads(decoded_data)
                    return {
                        'status': status_code,
                        'data': parsed_data
                    }
                except json.JSONDecodeError:
                    pass
            
            return {
                'status': status_code,
                'data': decoded_data
            }
    
    except urllib.error.HTTPError as e:
        return {
            'status': e.code,
            'data': f'HTTP Error: {e.reason}'
        }
    
    except urllib.error.URLError as e:
        raise Exception(f'URL Error fetching {url}: {str(e.reason)}')
    
    except Exception as e:
        raise Exception(f'Error fetching {url}: {str(e)}')